/**
 * Admin Settings Page
 * Author: generated by Amazon Q
 * Created: 2024-12-20
 */

'use client';

import { useState, useEffect } from 'react';
import { Button } from '@/components/ui/Button';
import { Card } from '@/components/ui/Card';
import { Input } from '@/components/ui/Input';
import { Label } from '@/components/ui/Label';
import { Switch } from '@/components/ui/Switch';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/Select';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/Tabs';
import { Upload, Save, RotateCcw, Settings, Image, Globe, Phone, Palette, Star } from 'lucide-react';
import { useImageUpload } from '@/hooks/useImageUpload';

interface SiteSettings {
  logo: {
    lightUrl: string;
    darkUrl: string;
    alt: string;
    width: number;
    height: number;
  };
  languages: {
    showInHeader: boolean;
    defaultLanguage: string;
    enabledLanguages: string[];
  };
  contactSales: {
    show: boolean;
    text: string;
    url: string;
  };
  theme: {
    defaultTheme: 'light' | 'dark' | 'system';
    autoSwitchByTime: boolean;
    darkModeStart: string;
    darkModeEnd: string;
  };
  favicon: {
    url: string;
    appleTouchIcon: string;
    manifest: string;
  };
}

const defaultSettings: SiteSettings = {
  logo: {
    lightUrl: '',
    darkUrl: '',
    alt: 'English Website',
    width: 120,
    height: 40
  },
  languages: {
    showInHeader: true,
    defaultLanguage: 'en',
    enabledLanguages: ['en', 'ar']
  },
  contactSales: {
    show: true,
    text: 'Contact Sales',
    url: '/contact-sales'
  },
  theme: {
    defaultTheme: 'light',
    autoSwitchByTime: false,
    darkModeStart: '18:00',
    darkModeEnd: '06:00'
  },
  favicon: {
    url: '/favicon.ico',
    appleTouchIcon: '/apple-touch-icon.png',
    manifest: '/site.webmanifest'
  }
};

export default function SettingsPage() {
  const [settings, setSettings] = useState<SiteSettings>(defaultSettings);
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);

  const lightLogoUpload = useImageUpload({
    type: 'logo-light',
    onSuccess: (url) => {
      setSettings(prev => ({
        ...prev,
        logo: { ...prev.logo, lightUrl: url }
      }));
    },
    onError: (error) => {
      console.error('Light logo upload failed:', error);
      alert(`Failed to upload light logo: ${error}`);
    }
  });

  const darkLogoUpload = useImageUpload({
    type: 'logo-dark',
    onSuccess: (url) => {
      setSettings(prev => ({
        ...prev,
        logo: { ...prev.logo, darkUrl: url }
      }));
    },
    onError: (error) => {
      console.error('Dark logo upload failed:', error);
      alert(`Failed to upload dark logo: ${error}`);
    }
  });

  const faviconUpload = useImageUpload({
    type: 'favicon',
    onSuccess: (url) => {
      setSettings(prev => ({
        ...prev,
        favicon: { ...prev.favicon, url }
      }));
    },
    onError: (error) => {
      console.error('Favicon upload failed:', error);
      alert(`Failed to upload favicon: ${error}`);
    }
  });

  useEffect(() => {
    loadSettings();
  }, []);

  const loadSettings = async () => {
    try {
      const response = await fetch('/api/admin/settings');
      if (response.ok) {
        const data = await response.json();
        const mergedSettings = { ...defaultSettings, ...data };
        setSettings(mergedSettings);
        
        // Set previews for existing images without cache busting initially
        if (mergedSettings.logo?.lightUrl) {
          lightLogoUpload.setPreview(mergedSettings.logo.lightUrl);
        }
        
        if (mergedSettings.logo?.darkUrl) {
          darkLogoUpload.setPreview(mergedSettings.logo.darkUrl);
        }
        
        if (mergedSettings.favicon?.url) {
          faviconUpload.setPreview(mergedSettings.favicon.url);
        }
      } else {
        console.error('Failed to load settings:', response.statusText);
      }
    } catch (error) {
      console.error('Failed to load settings:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const saveSettings = async () => {
    setIsSaving(true);
    try {
      const response = await fetch('/api/admin/settings', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(settings)
      });

      if (response.ok) {
        // Show success message
        alert('Settings saved successfully!');
      } else {
        throw new Error('Failed to save settings');
      }
    } catch (error) {
      console.error('Failed to save settings:', error);
      alert('Failed to save settings. Please try again.');
    } finally {
      setIsSaving(false);
    }
  };

  const resetSettings = () => {
    if (confirm('Are you sure you want to reset all settings to default?')) {
      setSettings(defaultSettings);
      lightLogoUpload.clearPreview();
      darkLogoUpload.clearPreview();
      faviconUpload.clearPreview();
      // Also clear the URLs in settings
      setSettings(prev => ({
        ...prev,
        logo: { ...prev.logo, lightUrl: '', darkUrl: '' },
        favicon: { ...prev.favicon, url: '/favicon.ico' }
      }));
    }
  };

  const handleLightLogoUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      try {
        await lightLogoUpload.uploadImage(file);
        event.target.value = '';
      } catch (error) {
        console.error('Light logo upload error:', error);
        event.target.value = '';
      }
    }
  };

  const handleDarkLogoUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      try {
        await darkLogoUpload.uploadImage(file);
        event.target.value = '';
      } catch (error) {
        console.error('Dark logo upload error:', error);
        event.target.value = '';
      }
    }
  };

  const handleFaviconUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      try {
        await faviconUpload.uploadImage(file);
        // Clear the input so the same file can be selected again if needed
        event.target.value = '';
      } catch (error) {
        console.error('Favicon upload error:', error);
        event.target.value = '';
      }
    }
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-8 max-w-4xl">
      <div className="flex items-center justify-between mb-8">
        <div className="flex items-center gap-3">
          <Settings className="h-8 w-8 text-blue-600" />
          <h1 className="text-3xl font-bold text-gray-900 dark:text-white">Site Settings</h1>
        </div>
        <div className="flex gap-3">
          <Button variant="outline" onClick={resetSettings}>
            <RotateCcw className="h-4 w-4 mr-2" />
            Reset to Default
          </Button>
          <Button onClick={saveSettings} disabled={isSaving}>
            <Save className="h-4 w-4 mr-2" />
            {isSaving ? 'Saving...' : 'Save Settings'}
          </Button>
        </div>
      </div>

      <Tabs defaultValue="logo" className="space-y-6">
        <TabsList className="grid w-full grid-cols-5">
          <TabsTrigger value="logo" className="flex items-center gap-2">
            <Image className="h-4 w-4" />
            Logo
          </TabsTrigger>
          <TabsTrigger value="languages" className="flex items-center gap-2">
            <Globe className="h-4 w-4" />
            Languages
          </TabsTrigger>
          <TabsTrigger value="contact" className="flex items-center gap-2">
            <Phone className="h-4 w-4" />
            Contact Sales
          </TabsTrigger>
          <TabsTrigger value="theme" className="flex items-center gap-2">
            <Palette className="h-4 w-4" />
            Theme
          </TabsTrigger>
          <TabsTrigger value="favicon" className="flex items-center gap-2">
            <Star className="h-4 w-4" />
            Favicon
          </TabsTrigger>
        </TabsList>

        {/* Logo Settings */}
        <TabsContent value="logo">
          <Card className="p-6">
            <h2 className="text-xl font-semibold mb-4">Logo Configuration</h2>
            <div className="space-y-8">
              {/* Light Theme Logo */}
              <div>
                <h3 className="text-lg font-medium mb-4 flex items-center gap-2">
                  <div className="w-4 h-4 bg-white border border-gray-300 rounded"></div>
                  Light Theme Logo
                </h3>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-4">
                    <div>
                      <Label htmlFor="light-logo-upload">Upload Light Logo</Label>
                      <div className="mt-2">
                        <input
                          id="light-logo-upload"
                          type="file"
                          accept="image/*,.webp"
                          onChange={handleLightLogoUpload}
                          className="hidden"
                        />
                        <Button
                          variant="outline"
                          onClick={() => document.getElementById('light-logo-upload')?.click()}
                          className="w-full"
                        >
                          <Upload className="h-4 w-4 mr-2" />
                          Choose Light Logo
                        </Button>
                      </div>
                    </div>
                  </div>
                  <div className="flex items-center justify-center">
                    {(lightLogoUpload.preview || settings.logo.lightUrl) ? (
                      <div className="border-2 border-dashed border-gray-300 rounded-lg p-4 bg-white">
                        <img
                          key={`light-logo-${Date.now()}`}
                          src={lightLogoUpload.preview || `${settings.logo.lightUrl}?v=${Date.now()}`}
                          alt={settings.logo.alt || 'Light logo preview'}
                          className="max-w-full h-auto"
                          style={{
                            maxWidth: `${settings.logo.width}px`,
                            maxHeight: `${settings.logo.height}px`
                          }}
                          onLoad={() => {
                            // Force re-render after image loads
                            console.log('Light logo loaded successfully');
                          }}
                        />
                        {lightLogoUpload.isUploading && (
                          <div className="mt-2 text-center text-sm text-blue-600">Uploading...</div>
                        )}
                      </div>
                    ) : (
                      <div className="border-2 border-dashed border-gray-300 rounded-lg p-8 text-center text-gray-500 bg-white">
                        <Image className="h-12 w-12 mx-auto mb-2" />
                        <p>No light logo uploaded</p>
                      </div>
                    )}
                  </div>
                </div>
              </div>

              {/* Dark Theme Logo */}
              <div>
                <h3 className="text-lg font-medium mb-4 flex items-center gap-2">
                  <div className="w-4 h-4 bg-gray-800 rounded"></div>
                  Dark Theme Logo
                </h3>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-4">
                    <div>
                      <Label htmlFor="dark-logo-upload">Upload Dark Logo</Label>
                      <div className="mt-2">
                        <input
                          id="dark-logo-upload"
                          type="file"
                          accept="image/*,.webp"
                          onChange={handleDarkLogoUpload}
                          className="hidden"
                        />
                        <Button
                          variant="outline"
                          onClick={() => document.getElementById('dark-logo-upload')?.click()}
                          className="w-full"
                        >
                          <Upload className="h-4 w-4 mr-2" />
                          Choose Dark Logo
                        </Button>
                      </div>
                    </div>
                  </div>
                  <div className="flex items-center justify-center">
                    {(darkLogoUpload.preview || settings.logo.darkUrl) ? (
                      <div className="border-2 border-dashed border-gray-300 rounded-lg p-4 bg-gray-800">
                        <img
                          key={`dark-logo-${Date.now()}`}
                          src={darkLogoUpload.preview || `${settings.logo.darkUrl}?v=${Date.now()}`}
                          alt={settings.logo.alt || 'Dark logo preview'}
                          className="max-w-full h-auto"
                          style={{
                            maxWidth: `${settings.logo.width}px`,
                            maxHeight: `${settings.logo.height}px`
                          }}
                          onLoad={() => {
                            // Force re-render after image loads
                            console.log('Dark logo loaded successfully');
                          }}
                        />
                        {darkLogoUpload.isUploading && (
                          <div className="mt-2 text-center text-sm text-blue-600">Uploading...</div>
                        )}
                      </div>
                    ) : (
                      <div className="border-2 border-dashed border-gray-300 rounded-lg p-8 text-center text-gray-500 bg-gray-800">
                        <Image className="h-12 w-12 mx-auto mb-2 text-white" />
                        <p className="text-white">No dark logo uploaded</p>
                      </div>
                    )}
                  </div>
                </div>
              </div>

              {/* Common Settings */}
              <div>
                <h3 className="text-lg font-medium mb-4">Common Settings</h3>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  <div>
                    <Label htmlFor="logo-alt">Alt Text</Label>
                    <Input
                      id="logo-alt"
                      value={settings.logo.alt}
                      onChange={(e) => setSettings(prev => ({
                        ...prev,
                        logo: { ...prev.logo, alt: e.target.value }
                      }))}
                    />
                  </div>
                  <div>
                    <Label htmlFor="logo-width">Width (px)</Label>
                    <Input
                      id="logo-width"
                      type="number"
                      value={settings.logo.width}
                      onChange={(e) => setSettings(prev => ({
                        ...prev,
                        logo: { ...prev.logo, width: parseInt(e.target.value) || 120 }
                      }))}
                    />
                  </div>
                  <div>
                    <Label htmlFor="logo-height">Height (px)</Label>
                    <Input
                      id="logo-height"
                      type="number"
                      value={settings.logo.height}
                      onChange={(e) => setSettings(prev => ({
                        ...prev,
                        logo: { ...prev.logo, height: parseInt(e.target.value) || 40 }
                      }))}
                    />
                  </div>
                </div>
              </div>
            </div>
          </Card>
        </TabsContent>

        {/* Languages Settings */}
        <TabsContent value="languages">
          <Card className="p-6">
            <h2 className="text-xl font-semibold mb-4">Language Configuration</h2>
            <div className="space-y-6">
              <div className="flex items-center justify-between">
                <div>
                  <Label>Show Language Selector in Header</Label>
                  <p className="text-sm text-gray-600 mt-1">Display language switcher in the main navigation</p>
                </div>
                <Switch
                  checked={settings.languages.showInHeader}
                  onCheckedChange={(checked) => setSettings(prev => ({
                    ...prev,
                    languages: { ...prev.languages, showInHeader: checked }
                  }))}
                />
              </div>

              <div>
                <Label htmlFor="default-language">Default Language</Label>
                <Select
                  value={settings.languages.defaultLanguage}
                  onValueChange={(value) => setSettings(prev => ({
                    ...prev,
                    languages: { ...prev.languages, defaultLanguage: value }
                  }))}
                >
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="en">English</SelectItem>
                    <SelectItem value="ar">العربية</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div>
                <Label>Enabled Languages</Label>
                <div className="mt-2 space-y-2">
                  {['en', 'ar'].map((lang) => (
                    <div key={lang} className="flex items-center space-x-2">
                      <input
                        type="checkbox"
                        id={`lang-${lang}`}
                        checked={settings.languages.enabledLanguages.includes(lang)}
                        onChange={(e) => {
                          const enabled = settings.languages.enabledLanguages;
                          if (e.target.checked) {
                            setSettings(prev => ({
                              ...prev,
                              languages: {
                                ...prev.languages,
                                enabledLanguages: [...enabled, lang]
                              }
                            }));
                          } else {
                            setSettings(prev => ({
                              ...prev,
                              languages: {
                                ...prev.languages,
                                enabledLanguages: enabled.filter(l => l !== lang)
                              }
                            }));
                          }
                        }}
                        className="rounded border-gray-300"
                      />
                      <Label htmlFor={`lang-${lang}`}>
                        {lang === 'en' ? 'English' : 'العربية'}
                      </Label>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </Card>
        </TabsContent>

        {/* Contact Sales Settings */}
        <TabsContent value="contact">
          <Card className="p-6">
            <h2 className="text-xl font-semibold mb-4">Contact Sales Configuration</h2>
            <div className="space-y-6">
              <div className="flex items-center justify-between">
                <div>
                  <Label>Show Contact Sales Button</Label>
                  <p className="text-sm text-gray-600 mt-1">Display contact sales button in the header</p>
                </div>
                <Switch
                  checked={settings.contactSales.show}
                  onCheckedChange={(checked) => setSettings(prev => ({
                    ...prev,
                    contactSales: { ...prev.contactSales, show: checked }
                  }))}
                />
              </div>

              <div>
                <Label htmlFor="contact-text">Button Text</Label>
                <Input
                  id="contact-text"
                  value={settings.contactSales.text}
                  onChange={(e) => setSettings(prev => ({
                    ...prev,
                    contactSales: { ...prev.contactSales, text: e.target.value }
                  }))}
                />
              </div>

              <div>
                <Label htmlFor="contact-url">Button URL</Label>
                <Input
                  id="contact-url"
                  value={settings.contactSales.url}
                  onChange={(e) => setSettings(prev => ({
                    ...prev,
                    contactSales: { ...prev.contactSales, url: e.target.value }
                  }))}
                />
              </div>
            </div>
          </Card>
        </TabsContent>

        {/* Theme Settings */}
        <TabsContent value="theme">
          <Card className="p-6">
            <h2 className="text-xl font-semibold mb-4">Theme Configuration</h2>
            <div className="space-y-6">
              <div>
                <Label htmlFor="default-theme">Default Theme</Label>
                <Select
                  value={settings.theme.defaultTheme}
                  onValueChange={(value) => setSettings(prev => ({
                    ...prev,
                    theme: { ...prev.theme, defaultTheme: value as 'light' | 'dark' | 'system' }
                  }))}
                >
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="light">Light</SelectItem>
                    <SelectItem value="dark">Dark</SelectItem>
                    <SelectItem value="system">System</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div className="flex items-center justify-between">
                <div>
                  <Label>Auto Switch by Time</Label>
                  <p className="text-sm text-gray-600 mt-1">Automatically switch theme based on time</p>
                </div>
                <Switch
                  checked={settings.theme.autoSwitchByTime}
                  onCheckedChange={(checked) => setSettings(prev => ({
                    ...prev,
                    theme: { ...prev.theme, autoSwitchByTime: checked }
                  }))}
                />
              </div>

              {settings.theme.autoSwitchByTime && (
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <Label htmlFor="dark-start">Dark Mode Start</Label>
                    <Input
                      id="dark-start"
                      type="time"
                      value={settings.theme.darkModeStart}
                      onChange={(e) => setSettings(prev => ({
                        ...prev,
                        theme: { ...prev.theme, darkModeStart: e.target.value }
                      }))}
                    />
                  </div>
                  <div>
                    <Label htmlFor="dark-end">Dark Mode End</Label>
                    <Input
                      id="dark-end"
                      type="time"
                      value={settings.theme.darkModeEnd}
                      onChange={(e) => setSettings(prev => ({
                        ...prev,
                        theme: { ...prev.theme, darkModeEnd: e.target.value }
                      }))}
                    />
                  </div>
                </div>
              )}
            </div>
          </Card>
        </TabsContent>

        {/* Favicon Settings */}
        <TabsContent value="favicon">
          <Card className="p-6">
            <h2 className="text-xl font-semibold mb-4">Favicon Configuration</h2>
            <div className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-4">
                  <div>
                    <Label htmlFor="favicon-upload">Upload Favicon</Label>
                    <p className="text-sm text-gray-600 mt-1">Recommended: 32x32 or 16x16 pixels, ICO or PNG format</p>
                    <div className="mt-2">
                      <input
                        id="favicon-upload"
                        type="file"
                        accept=".ico,.png,.svg,.webp"
                        onChange={handleFaviconUpload}
                        className="hidden"
                      />
                      <Button
                        variant="outline"
                        onClick={() => document.getElementById('favicon-upload')?.click()}
                        className="w-full"
                      >
                        <Upload className="h-4 w-4 mr-2" />
                        Choose Favicon File
                      </Button>
                    </div>
                  </div>

                  <div>
                    <Label htmlFor="favicon-url">Favicon URL</Label>
                    <Input
                      id="favicon-url"
                      value={settings.favicon.url}
                      onChange={(e) => setSettings(prev => ({
                        ...prev,
                        favicon: { ...prev.favicon, url: e.target.value }
                      }))}
                      placeholder="/favicon.ico"
                    />
                  </div>

                  <div>
                    <Label htmlFor="apple-touch-icon">Apple Touch Icon</Label>
                    <Input
                      id="apple-touch-icon"
                      value={settings.favicon.appleTouchIcon}
                      onChange={(e) => setSettings(prev => ({
                        ...prev,
                        favicon: { ...prev.favicon, appleTouchIcon: e.target.value }
                      }))}
                      placeholder="/apple-touch-icon.png"
                    />
                  </div>

                  <div>
                    <Label htmlFor="manifest">Web App Manifest</Label>
                    <Input
                      id="manifest"
                      value={settings.favicon.manifest}
                      onChange={(e) => setSettings(prev => ({
                        ...prev,
                        favicon: { ...prev.favicon, manifest: e.target.value }
                      }))}
                      placeholder="/site.webmanifest"
                    />
                  </div>
                </div>

                <div className="flex items-center justify-center">
                  {(faviconUpload.preview || settings.favicon.url) ? (
                    <div className="border-2 border-dashed border-gray-300 rounded-lg p-4">
                      <img
                        key={`favicon-${Date.now()}`}
                        src={faviconUpload.preview || `${settings.favicon.url}?v=${Date.now()}`}
                        alt="Favicon preview"
                        className="w-8 h-8 mx-auto"
                        onLoad={() => {
                          console.log('Favicon loaded successfully');
                        }}
                        onError={(e) => {
                          const target = e.target as HTMLImageElement;
                          target.style.display = 'none';
                          const parent = target.parentElement;
                          if (parent && !parent.querySelector('.error-message')) {
                            const errorDiv = document.createElement('div');
                            errorDiv.className = 'error-message text-red-500 text-sm text-center';
                            errorDiv.textContent = 'Failed to load favicon';
                            parent.appendChild(errorDiv);
                          }
                        }}
                      />
                      <p className="text-sm text-gray-600 mt-2 text-center">Favicon Preview</p>
                      {faviconUpload.isUploading && (
                        <div className="mt-2 text-center text-sm text-blue-600">Uploading...</div>
                      )}
                    </div>
                  ) : (
                    <div className="border-2 border-dashed border-gray-300 rounded-lg p-8 text-center text-gray-500">
                      <Star className="h-12 w-12 mx-auto mb-2" />
                      <p>No favicon uploaded</p>
                    </div>
                  )}
                </div>
              </div>
            </div>
          </Card>
        </TabsContent>
      </Tabs>
    </div>
  );
}